import type { HTMLAttributes } from 'react';
import { TestComponentProps } from 'src/types/test-component';
/**
 * Публичные пропсы компонента Tag.
 */
export interface TagProps extends HTMLAttributes<HTMLDivElement>, TestComponentProps {
    /**
     * Текст тега. Отображается внутри компонента через Typography с variant="body3".
     */
    label: string;
    /**
     * Обработчик клика по кнопке удаления.
     */
    onRemove?: () => void;
    /**
     * aria-label для кнопки удаления.
     * Если не указан, будет сгенерирован из значения label.
     */
    removeAriaLabel?: string;
}
